import * as React from "react";

export interface TdNavItem {
  label: string;
  href: string;
}

export interface TdNavProps {
  brand: string;
  brandHref?: string;
  items: TdNavItem[];
  cta?: { label: string; href: string };
  className?: string;
}

export function TdNav({ brand, brandHref = "/", items, cta, className = "" }: TdNavProps) {
  return (
    <header
      className={`w-full border-b bg-white/90 backdrop-blur supports-[backdrop-filter]:bg-white/70 ${className}`.trim()}
      style={{ borderColor: "var(--td-border, rgba(15,23,42,0.08))" }}
    >
      <nav className="mx-auto flex max-w-6xl items-center justify-between gap-6 px-6 py-4">
        <a
          href={brandHref}
          className="text-lg font-semibold tracking-tight"
          style={{ color: "var(--td-primary, #2E6554)" }}
        >
          {brand}
        </a>
        <ul className="hidden items-center gap-7 md:flex">
          {items.map((item) => (
            <li key={item.href}>
              <a
                href={item.href}
                className="text-sm font-medium text-slate-700 transition-colors hover:text-[var(--td-primary,#2E6554)]"
              >
                {item.label}
              </a>
            </li>
          ))}
        </ul>
        {cta ? (
          <a
            href={cta.href}
            className="inline-flex h-10 items-center rounded-md px-4 text-sm font-medium text-white transition-opacity hover:opacity-90"
            style={{ backgroundColor: "var(--td-primary, #2E6554)" }}
          >
            {cta.label}
          </a>
        ) : (
          <span className="hidden md:inline-block w-0" aria-hidden />
        )}
      </nav>
    </header>
  );
}

export default TdNav;
